		"html": "<section class=\"fsp-slide\" data-label=\"Ask Questions. Earn Coins.\" data-speaker-notes=\"Genuine invitation — anonymous, no wrong questions, every one earns a coin. Give them a minute to scan.\" style=\"background:var(--bg0);color:var(--white);font-family:'Rajdhani',sans-serif;overflow:hidden\">\n    <div data-texture=\"\" style=\"position:absolute;inset:0;pointer-events:none;opacity:calc(var(--tex,1)*1);background-image:linear-gradient(rgba(0,255,65,0.045) 1px,transparent 1px),linear-gradient(90deg,rgba(0,255,65,0.045) 1px,transparent 1px);background-size:48px 48px;animation:fsp-gridpan 26s linear infinite\"></div>\n    <div data-texture=\"\" style=\"position:absolute;inset:0;pointer-events:none;opacity:calc(var(--tex,1)*1);background:radial-gradient(ellipse 70% 55% at 78% 50%,rgba(0,255,65,0.06),transparent 60%);animation:fsp-glowdrift 13s ease-in-out infinite\"></div>\n    <div style=\"position:absolute;top:80px;left:90px;right:90px;bottom:120px;display:grid;grid-template-columns:1fr 490px;gap:80px;align-items:center\">\n      <div style=\"display:flex;flex-direction:column;gap:34px\">\n        <div class=\"ds-in-rise ds-d1\" style=\"font-family:'Share Tech Mono',monospace;font-size:24px;letter-spacing:0.22em;text-transform:uppercase;color:var(--green);text-shadow:var(--glow-green)\">// Q&amp;A</div>\n        <h1 class=\"ds-in-rise ds-d2\" style=\"margin:0;font-size:86px;font-weight:700;line-height:1.02;color:var(--white)\"><span>Have a question?</span><br><span style=\"color:var(--green);text-shadow:var(--glow-green)\">Ask it.</span></h1>\n        <div style=\"height:1px;background:var(--line)\"></div>\n        <p style=\"margin:0;font-size:33px;line-height:1.45;color:var(--white)\">Anonymous submissions appear live on screen.</p>\n        <p style=\"margin:0;font-size:33px;line-height:1.45;color:var(--white)\"><span>Every question earns an </span><b style=\"color:var(--green);text-shadow:var(--glow-green)\">IDEA Coin.</b></p>\n      </div>\n      <div style=\"display:flex;flex-direction:column;gap:20px;align-items:center;padding:30px;border:1px solid var(--line-strong);border-radius:4px;background:var(--bg1);box-shadow:var(--bevel-raised), 0 0 34px rgba(0,255,65,0.1)\">\n        <div style=\"position:relative;width:410px;height:410px;background:#fff;border-radius:3px;padding:16px;display:flex;align-items:center;justify-content:center\"><img class=\"qr\" src=\"/fsp/fsp-ask-qr.svg\" alt=\"Scan to submit a question at ideabosco.com/fsp/ask\" style=\"width:378px;height:378px;display:block\" /></div>\n        <span style=\"font-family:'Share Tech Mono',monospace;font-size:26px;letter-spacing:0.18em;color:var(--green);text-shadow:var(--glow-green)\">SCAN TO SUBMIT</span>\n        <span style=\"font-family:'Share Tech Mono',monospace;font-size:24px;letter-spacing:0.12em;color:var(--dim)\">ANONYMOUS // IDEA-APP FORM</span>\n      </div>\n    </div>\n    <div style=\"position:absolute;left:90px;right:90px;bottom:38px;display:flex;align-items:center;justify-content:space-between;font-family:'Share Tech Mono',monospace;font-size:24px;letter-spacing:0.12em;color:var(--dim)\"><span>IDEA // FSP · SUMMER 2026</span><span style=\"display:block;width:118px;opacity:0.92;filter:drop-shadow(0 0 10px rgba(0,255,65,0.22))\"><span class=\"idea-wordmark\" style=\"font-size:47px;line-height:0.8\">IDEA</span></span><span>DWG 013 / 014 · REV A</span></div>\n  </section>"
